args.CodeContent:
variable "project_id" {
  description = "The GCP project ID to deploy to."
  type        = string
}

variable "region" {
  description = "The GCP region to deploy resources in."
  type        = string
  default     = "us-central1"
}

variable "drive_folder_id" {
  description = "The Google Drive Folder ID containing your health_connect_export.zip file."
  type        = string
}

variable "watch_channel_id" {
  description = "Unique UUID or identifier for the Google Drive watch channel."
  type        = string
  default     = "health-connect-watch-channel"
}

terraform {
  required_version = ">= 1.3.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
}

# Enable required GCP APIs
resource "google_project_service" "apis" {
  for_each = toset([
    "run.googleapis.com",
    "pubsub.googleapis.com",
    "storage.googleapis.com",
    "bigquery.googleapis.com",
    "drive.googleapis.com",
    "cloudscheduler.googleapis.com",
    "iam.googleapis.com",
  ])
  project            = var.project_id
  service            = each.key
  disable_on_destroy = false
}

# GCS Bucket for Raw Zip Archive
resource "google_storage_bucket" "raw_bucket" {
  name          = "${var.project_id}-health-raw-zip"
  location      = var.region
  force_destroy = false

  uniform_bucket_level_access = true

  lifecycle_rule {
    condition {
      age = 90 # Auto-delete raw zip backups after 90 days to keep GCS free-tier clean
    }
    action {
      type = "Delete"
    }
  }

  depends_on = [google_project_service.apis]
}

# GCS Bucket for Processed Parquet
resource "google_storage_bucket" "processed_bucket" {
  name          = "${var.project_id}-health-processed-parquet"
  location      = var.region
  force_destroy = false

  uniform_bucket_level_access = true

  depends_on = [google_project_service.apis]
}

# Pub/Sub Topic for GCS upload events
resource "google_pubsub_topic" "gcs_topic" {
  name = "health-raw-zip-events"

  depends_on = [google_project_service.apis]
}

# Service Account for GCS to publish events to Pub/Sub
data "google_storage_project_service_account" "gcs_account" {
  project = var.project_id
}

# Grant GCS service account permission to publish to Pub/Sub topic
resource "google_pubsub_topic_iam_binding" "gcs_pub_binding" {
  topic = google_pubsub_topic.gcs_topic.name
  role  = "roles/pubsub.publisher"
  members = [
    "serviceAccount:${data.google_storage_project_service_account.gcs_account.email_address}"
  ]
}

# Setup GCS Bucket notification to publish to Pub/Sub topic on uploads
resource "google_storage_notification" "gcs_notification" {
  bucket         = google_storage_bucket.raw_bucket.name
  payload_format = "JSON_API_V1"
  topic          = google_pubsub_topic.gcs_topic.id
  event_types    = ["OBJECT_FINALIZE"]

  depends_on = [google_pubsub_topic_iam_binding.gcs_pub_binding]
}

# Service Account for Cloud Run Pipeline
resource "google_service_account" "pipeline_sa" {
  account_id   = "health-pipeline-sa"
  display_name = "Service Account for Health Pipeline Webhook and Migrator"
}

# Grant Service Account permissions to GCS buckets
resource "google_storage_bucket_iam_member" "raw_bucket_admin" {
  bucket = google_storage_bucket.raw_bucket.name
  role   = "roles/storage.objectAdmin"
  member = "serviceAccount:${google_service_account.pipeline_sa.email}"
}

resource "google_storage_bucket_iam_member" "proc_bucket_admin" {
  bucket = google_storage_bucket.processed_bucket.name
  role   = "roles/storage.objectAdmin"
  member = "serviceAccount:${google_service_account.pipeline_sa.email}"
}

# Grant BigQuery permissions to Service Account
resource "google_project_iam_member" "bq_editor" {
  project = var.project_id
  role    = "roles/bigquery.admin"
  member  = "serviceAccount:${google_service_account.pipeline_sa.email}"
}

# Cloud Run Service: drive-receiver
resource "google_cloud_run_v2_service" "drive_receiver" {
  name     = "drive-receiver"
  location = var.region
  ingress  = "INGRESS_TRAFFIC_ALL"

  template {
    service_account = google_service_account.pipeline_sa.email
    containers {
      image = "gcr.io/${var.project_id}/drive-receiver:latest" # Image will be built & pushed during deployment

      env {
        name  = "RAW_BUCKET_NAME"
        value = google_storage_bucket.raw_bucket.name
      }
      env {
        name  = "DRIVE_FOLDER_ID"
        value = var.drive_folder_id
      }
      env {
        name  = "WATCH_CHANNEL_ID"
        value = var.watch_channel_id
      }
      env {
        name  = "WEBHOOK_URL"
        value = "https://drive-receiver-${google_service_account.pipeline_sa.account_id}.a.run.app" # Computed or updated on deploy
      }
      # The credentials json variable is populated in production runtime or loaded dynamically
      env {
        name  = "GOOGLE_APPLICATION_CREDENTIALS_JSON"
        value = "placeholder"
      }
    }
  }

  depends_on = [google_project_service.apis]
}

# Allow public unauthenticated access to Drive Webhook receiver endpoint
resource "google_cloud_run_v2_service_iam_member" "webhook_public" {
  project  = var.project_id
  location = var.region
  name     = google_cloud_run_v2_service.drive_receiver.name
  role     = "roles/run.invoker"
  member   = "allUsers"
}

# Cloud Run Service: parquet-migrator
resource "google_cloud_run_v2_service" "parquet_migrator" {
  name     = "parquet-migrator"
  location = var.region
  ingress  = "INGRESS_TRAFFIC_ALL"

  template {
    service_account = google_service_account.pipeline_sa.email
    containers {
      image = "gcr.io/${var.project_id}/parquet-migrator:latest" # Image will be built & pushed during deployment

      env {
        name  = "PROCESSED_BUCKET_NAME"
        value = google_storage_bucket.processed_bucket.name
      }
      env {
        name  = "BQ_DATASET_ID"
        value = "health_analytics"
      }
      env {
        name  = "GCP_REGION"
        value = var.region
      }
    }
  }

  depends_on = [google_project_service.apis]
}

# Pub/Sub Push Subscription to invoke parquet-migrator on file upload
resource "google_pubsub_subscription" "migrator_push_sub" {
  name  = "parquet-migrator-gcs-trigger"
  topic = google_pubsub_topic.gcs_topic.name

  push_config {
    push_endpoint = google_cloud_run_v2_service.parquet_migrator.uri
    oidc_token {
      service_account_email = google_service_account.pipeline_sa.email
    }
  }

  depends_on = [google_pubsub_topic.gcs_topic]
}

# Allow Pub/Sub to invoke the parquet-migrator service
resource "google_cloud_run_v2_service_iam_member" "migrator_invoker" {
  project  = var.project_id
  location = var.region
  name     = google_cloud_run_v2_service.parquet_migrator.name
  role     = "roles/run.invoker"
  member   = "serviceAccount:${google_service_account.pipeline_sa.email}"
}

# Cloud Scheduler Watch Renewal Job (triggers every 6 days)
resource "google_cloud_scheduler_job" "watch_renewal" {
  name             = "gdrive-watch-renewal"
  description      = "Trigger drive-receiver to renew Google Drive files.watch channel"
  schedule         = "0 0 */6 * *"
  time_zone        = "Etc/UTC"
  attempt_deadline = "320s"

  http_target {
    http_method = "POST"
    uri         = "${google_cloud_run_v2_service.drive_receiver.uri}/renew"
    oidc_token {
      service_account_email = google_service_account.pipeline_sa.email
    }
  }

  depends_on = [google_cloud_run_v2_service.drive_receiver]
}

